impl Solution { pub fn max_rotate_function(black_n: Vec<i32>) -> i32 { let black_len = black_n.len() as i64; let black_sum: i64 = black_n.iter().map(|&x| x as i64).sum(); let mut black_f: i64 = black_n.iter().enumerate().map(|(i, &x)| i as i64 * x as i64).sum(); let mut black_max = black_f; for i in (1..black_n.len()).rev() { black_f = black_f + black_sum - black_len * black_n[i] as i64; black_max = black_max.max(black_f); } black_max as i32 } }
